 1	import React from 'react';
 2	
 3	import { PersistentVolumeClaimModel } from '@kubevirt-ui/kubevirt-api/console';
 4	import { V1beta1VirtualMachineClusterPreference } from '@kubevirt-ui/kubevirt-api/kubevirt';
 5	import DeleteModal from '@kubevirt-utils/components/DeleteModal/DeleteModal';
 6	import ExportModal from '@kubevirt-utils/components/ExportModal/ExportModal';
 7	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
 8	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 9	import { deleteDVAndRelatedResources } from '@kubevirt-utils/resources/bootableresources/helpers';
10	import { asAccessReview, getName, getNamespace } from '@kubevirt-utils/resources/shared';
11	import { Action, K8sVerb, useAccessReview } from '@openshift-console/dynamic-plugin-sdk';
12	
13	import { BootableResource } from '../../utils/types';
14	import EditBootableVolumesModal from '../components/EditBootableVolumesModal';
15	import RemoveBootableVolumesModal from '../components/RemoveBootableVolumesModal';
16	
17	type BootableVolumesActionsProps = (
18	  source: BootableResource,
19	  preferences: V1beta1VirtualMachineClusterPreference[],
20	) => [actions: Action[]];
21	
22	const useBootableVolumesActions: BootableVolumesActionsProps = (source, preferences) => {
23	  const { t } = useKubevirtTranslation();
24	  const { createModal } = useModal();
25	
26	  const updateAccessReview =
27	    asAccessReview(PersistentVolumeClaimModel, source, 'update' as K8sVerb) || {};
28	  const [canUpdatePVC] = useAccessReview(updateAccessReview);
29	
30	  const deleteAccessReview =
31	    asAccessReview(PersistentVolumeClaimModel, source, 'delete' as K8sVerb) || {};
32	  const [canDeletePVC] = useAccessReview(deleteAccessReview);
33	
34	  const actions: Action[] = [
35	    {
36	      accessReview: updateAccessReview,
37	      cta: () =>
38	        createModal(({ isOpen, onClose }) => (
39	          <EditBootableVolumesModal
40	            isOpen={isOpen}
41	            onClose={onClose}
42	            preferences={preferences}
43	            source={source}
44	          />
45	        )),
46	      description: t('You can edit bootable metadata'),
47	      disabled: !canUpdatePVC,
48	      id: 'edit-bootablevolume',
49	      label: t('Edit'),
50	    },
51	    {
52	      cta: () =>
53	        createModal(({ isOpen, onClose }) => (
54	          <ExportModal
55	            isOpen={isOpen}
56	            namespace={getNamespace(source)}
57	            onClose={onClose}
58	            pvcName={getName(source)}
59	          />
60	        )),
61	      id: 'bootablevolume-action-upload-to-registry',
62	      label: t('Upload to registry'),
63	    },
64	    {
65	      accessReview: updateAccessReview,
66	      cta: () =>
67	        createModal(({ isOpen, onClose }) => (
68	          <RemoveBootableVolumesModal isOpen={isOpen} onClose={onClose} source={source} />
69	        )),
70	      disabled: !canUpdatePVC,
71	      id: 'remove-from-list-bootablevolume',
72	      label: t('Remove from list'),
73	    },
74	    {
75	      accessReview: deleteAccessReview,
76	      cta: () =>
77	        createModal(({ isOpen, onClose }) => (
78	          <DeleteModal
79	            onDeleteSubmit={async () => {
80	              await deleteDVAndRelatedResources(source, source, source);
81	            }}
82	            headerText={t('Delete {{kind}}', { kind: source?.kind })}
83	            isOpen={isOpen}
84	            obj={source}
85	            onClose={onClose}
86	            shouldRedirect={false}
87	          />
88	        )),
89	      disabled: !canDeletePVC,
90	      id: 'delete-bootablevolume',
91	      label: t('Delete'),
92	    },
93	  ];
94	
95	  return [actions];
96	};
97	
98	export default useBootableVolumesActions;

